B.PM=s(["\xa1\xa1\xa1Buuu!!! \xa1\xa1\xa1Es una bomba!!!","\xa1\xa1Explosi\xf3n de esp\xedritus vengativos!!"],t.s)
B.Vd=s(["Jejeje... \xa1Go!","No ha terminado... Hasta el final del infierno..."],t.s)
B.abk=s(["Jeje... Suficiente.","Ya te he encadenado bastante..."],t.s)
B.a5t=s(["\xa1\xa1\xa1Jajajaja!!! \xa1Mi victoria!","Cosechar\xe9 tu alma..."],t.s)
B.V8=s(["Ooo... Desvaneci\xe9ndome...","\xbf\xa1Me est\xe1s diciendo que pase al otro lado?!"],t.s)
B.QP=s(["\xa1\xa1Kyaaaaak!! \xa1Me robaron el alma!","\xa1Qu\xe9 rencor...!"],t.s)
B.YX=s(["\xa1Urgh...! \xbf\xa1Una bomba de exorcismo?!","\xa1Mi forma se desmorona...!"],t.s)
B.Qu=s(["Ho-oh... \xbfMe seguir\xe1s al infierno?","No temas la maldici\xf3n..."],t.s)
B.Km=s(["Ugh... \xa1Este tipo es un demonio!","\xa1Huele a agua bendita...! \xa1Huyan!","Atrapa fantasmas, tiemblo...!"],t.s)
B.a2X=s(["\xa1\xa1Hasta la apuesta de mi alma fue robada!!","M\xe1s t\xf3xico que la parca..."],t.s)
B.acS=s(["Jeje... Apenas salvaste tu hilo de vida.","Tipo ins\xedpido..."],t.s)
B.a5P=s(["...Buena intuici\xf3n.","Nada mal..."],t.s)
B.WA=s(["\xa1Jejejek! \xa1Golpeaste el aire!","\xa1Atrapaste el viento!"],t.s)
B.ag_=new A.Q(B.x,[B.acq,B.Pj,B.PM,B.Vd,B.abk,B.a5t,B.V8,B.QP,B.YX,B.Qu,B.Km,B.a2X,B.acS,B.a5P,B.WA],t.M)
B.S5=s(["...Una cosecha.","La guada\xf1a de la muerte pasa.","El registro est\xe1 escrito."],t.s)
B.a9J=s(["No... es el momento a\xfan.","...","Se escap\xf3."],t.s)
B.a5O=s(["Bomba del inframundo...!","Llev\xe1ndolo todo... \xa1A cenizas!"],t.s)
B.Ue=s(["Go... La muerte espera.","A\xfan no... Hasta ahogar tu \xfaltimo aliento."],t.s)
B.acX=s(["Es suficiente... Te llevar\xe9 la pr\xf3xima vez.","Tu vida se ha extendido."],t.s)
B.a8B=s(["Era tu destino...","Nos vemos en el inframundo..."],t.s)
B.acF=s(["Hmph... Solo esta vez.","La muerte... Nunca pierde. Volver\xe9."],t.s)
B.a2v=s(["...\xa1Mi bot\xedn!","\xa1Insecto mortal!"],t.s)
B.a26=s(["\xa1Ugh...! \xa1Burl\xe1ndote de la Parca!","\xa1El m\xe1s all\xe1 tiembla...!"],t.s)
B.a8T=s(["Hmph, acortando tu propia vida.","Pasos hacia la muerte..."],t.s)
B.a3R=s(["\xa1E-esto no est\xe1 en el registro de la Parca!","\xbf\xa1Intentando cosecharme a m\xed?!","L-locura total..."],t.s)
B.a_z=s(["Mi l\xe1mpara de vida parpadea...","Maldito demonio..."],t.s)
B.a7D=s(["...Hmph, vida de rata.","Suplicando por tu vida con solo eso."],t.s)
B.a8r=s(["...\xbfLeyendo el destino?","Ojos agudos."],t.s)
B.a2j=s(["...\xbfNo puedes ver la sombra de la muerte?","Insensato."],t.s)
B.afY=new A.Q(B.x,[B.S5,B.a9J,B.a5O,B.Ue,B.acX,B.a8B,B.acF,B.a2v,B.a26,B.a8T,B.a3R,B.a_z,B.a7D,B.a8r,B.a2j],t.M)
B.a43=s(["Ya lo vi...","Como fue profetizado...","La luz estelar lo alcanz\xf3."],t.s)
B.a_a=s(["El futuro... est\xe1 temblando.","Esto tambi\xe9n es destino...","Las estrellas est\xe1n ocultas por nubes."],t.s)
B.VZ=s(["\xa1\xa1\xa1La ira del or\xe1culo!!!","\xa1Bomba del destino!"],t.s)
B.Qc=s(["El or\xe1culo dice... \xa1Go!","A\xfan no es el final, las estrellas lo quieren."],t.s)
B.a2y=s(["Las estrellas me dicen que pare.","Tu destino termina aqu\xed... por ahora."],t.s)
B.QZ=s(["Exactamente como fue profetizado~","La voluntad de las estrellas."],t.s)
B.a6Z=s(["\xbf\xa1El futuro... cambi\xf3?!","\xa1Esto no puede ser...! \xa1Un resultado que no est\xe1 en el libro de profec\xedas!"],t.s)
B.a0l=s(["\xa1Ah! \xa1Los engranajes del destino...!","\xa1Mi velo de luz estelar fue levantado!"],t.s)
B.TF=s(["\xa1\xa1Kyaaak!! \xa1La profec\xeda fall\xf3!","\xa1Un choque masivo de destinos...!"],t.s)
B.a6E=s(["Pretendes forjar tu propio futuro...","Las estrellas est\xe1n observando."],t.s)
B.Tu=s(["\xa1E-esto va m\xe1s all\xe1 de la profec\xeda...!","\xa1El hilo del destino se rompi\xf3...!","Una ruina aterradora se acerca..."],t.s)
B.VB=s(["Mi poder divino... se desvanece...","\xa1La profec\xeda de cat\xe1strofe era cierta!"],t.s)
B.a1_=s(["Parece que solo robaste un poco de destino.","Las estrellas est\xe1n aliviadas."],t.s)
B.KC=s(["\xbfEspiaste el futuro?","Excelente intuici\xf3n."],t.s)
B.Nj=s(["El destino no se ve tan f\xe1cilmente~","La luz estelar se burla de ti."],t.s)
B.afB=new A.Q(B.x,[B.a43,B.a_a,B.VZ,B.Qc,B.a2y,B.QZ,B.a6Z,B.a0l,B.TF,B.a6E,B.Tu,B.VB,B.a1_,B.KC,B.Nj],t.M)
B.a19=s(["\xa1Jajaja! \xa1Por supuesto!","\xa1El toque de un dios!","\xa1El universo me ayuda!"],t.s)
B.O8=s(["Hmph... Fall\xe9 por diversi\xf3n.","...","Piedad para un mortal."],t.s)
B.acg=s(["\xa1\xa1\xa1Castigo divino!!!","\xa1\xa1\xa1El universo explota!!! \xa1Autoridad divina!"],t.s)
B.PJ=s(["\xa1\xa1\xa1Go!!! \xa1El dios nunca se detiene!","\xa1Victoria sin fin! \xa1Infinito!"],t.s)
B.a0D=s(["Es suficiente... Por hoy.","\xa1Te conceder\xe9 piedad. Stop!"],t.s)
B.N8=s(["\xa1Jajaja! \xbf\xa1Desafiar a un dios?!","\xa1Un resultado natural! \xa1La providencia del universo!"],t.s)
B.Xp=s(["Esto... \xa1\xa1Imposible...!!","\xbf\xa1Qui\xe9n... qui\xe9n eres?! \xbf\xa1Un bug?!"],t.s)
B.Qj=s(["\xa1Ugh! \xa1Tomando el milagro de un dios!","\xa1\xa1Buuuuug!!"],t.s)
B.a7J=s(["\xa1\xa1Los cielos se derrumban!!","\xa1\xa1\xa1B-bug!!! \xa1Burl\xe1ndose de un dios!"],t.s)
B.UT=s(["Ho-oh~ \xa1Luchas bastante bien!","\xbfProbando la paciencia de un dios?"],t.s)
B.VO=s(["E-esto es capacidad humana...","\xa1M-mi c\xf3digo se enreda!!","\xa1Por favor perd\xf3name! \xa1\xa1\xa1Me degradar\xe1n de la divinidad!!!"],t.s)
B.N1=s(["El reino divino est\xe1 en bancarrota...","\xbf\xa1Usaste un truco, verdad?! \xa1\xa1Te banear\xe9!!"],t.s)
B.a5G=s(["\xa1Jaja! \xa1Intentando vencer a un dios con solo eso!","\xa1Una victoria trivial!"],t.s)
B.T2=s(["...\xbfDestino retorcido?","Un mono bastante inteligente."],t.s)
B.a0q=s(["\xa1Jajaja! \xa1El l\xedmite de un mortal!","\xa1Ca\xedste en mi cortina de humo divina!"],t.s)
B.a4M=s(["\xa1Jajaja! \xa1Pat\xe9tico no tener Gwang! \xa1Mortal!"],t.s)
